parameters.jsCode:
// Get the product array
const products = $input.first().json.items; 
const baseUrl = 'https://www.ggmgastro.com';

let htmlRows = '';

// Loop through products to build table rows/cards
products.forEach(p => {
  const fullLink = p.product_link.startsWith('http') ? p.product_link : baseUrl + p.product_link;

  htmlRows += `
    <div class="product-card" style="margin-bottom: 20px; border: 1px solid #eee; padding: 15px; border-radius: 8px; display: flex; align-items: center;">
      <img src="${p.image_link}" alt="${p.product_name}" style="width: 100px; height: 100px; object-fit: cover; border-radius: 4px; margin-right: 15px;">
      <div>
        <h3 style="margin: 0 0 5px 0; font-size: 16px; color: #333;">${p.product_name}</h3>
        <p style="margin: 0 0 10px 0; font-weight: bold; color: #ed1c24;">${p.price}</p>
        <a href="${fullLink}" style="background: #ed1c24; color: white; padding: 6px 12px; text-decoration: none; font-size: 12px; border-radius: 4px;">View Product</a>
      </div>
    </div>
  `;
});

// html body
const finalHtml = `
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <style>
        body { 
            font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; 
            line-height: 1.6; 
            color: #333333; 
            margin: 0; 
            padding: 0;
            background-color: #f4f4f4;
        }
        .wrapper {
            background-color: #f4f4f4;
            padding: 20px;
        }
        .container { 
            max-width: 600px; 
            margin: 0 auto; 
            background: #ffffff;
            border-radius: 12px; 
            overflow: hidden;
            box-shadow: 0 4px 10px rgba(0,0,0,0.05);
        }
        .header { 
            background-color: #ed1c24; 
            padding: 30px 20px; 
            text-align: center;
        }
        .header h2 { 
            color: #ffffff; 
            margin: 0; 
            font-size: 24px;
            letter-spacing: 1px;
        }
        .content {
            padding: 30px 20px;
        }
        .intro-text {
            font-size: 16px;
            margin-bottom: 25px;
        }
        /* Product Grid Area */
        .product-list {
            margin-top: 20px;
        }
        /* Individual Product Card Styling */
        .product-card { 
            border: 1px solid #e0e0e0; 
            border-radius: 8px; 
            margin-bottom: 20px; 
            padding: 15px;
            display: block; 
            text-decoration: none;
            transition: transform 0.2s;
        }
        .footer { 
            background-color: #f9f9f9;
            padding: 20px; 
            font-size: 13px; 
            color: #777777; 
            text-align: center;
            border-top: 1px solid #eeeeee;
        }
        .brand-link { 
            color: #ed1c24; 
            font-weight: bold; 
            text-decoration: none; 
        }
    </style>
</head>
<body>
    <div class="wrapper">
        <div class="container">
            <div class="header">
                <h2>Produktempfehlungen</h2>
            </div>

            <div class="content">
                <p class="intro-text">Sehr geehrte Kundin, sehr geehrter Kunde,</p>

                <p class="intro-text">Basierend auf Ihrer Beschreibung empfehlen wir Ihnen folgende professionelle Geräte für Ihr Unternehmen:</p>

                <div class="product-list">
                    ${htmlRows}
                </div>

                <p style="margin-top: 25px;">Sollten Sie Fragen zu diesen Artikeln haben, steht Ihnen unser Expertenteam gerne zur Verfügung.</p>
            </div>

            <div class="footer">
                <p>Herzliche Grüße,<br>
                <span style="color: #333; font-weight: bold;">GGM-Gastro Empfehlungsbot</span></p>
                <p>
                    <a href="https://www.ggmgastro.com/de-de-eur" class="brand-link">www.ggmgastro.com</a>
                </p>
            </div>
        </div>
    </div>
</body>
</html>
`;

return [{
  json: {
    htmlBody: finalHtml,
    products: products
  }
}];

